//! Spec-compliance tests: Table Style Resolution (ISO 29500-1 §17.4, §17.7.6)
//!
//! Tests verify table style conditional formatting, border conflict resolution,
//! and property inheritance through table style chains.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{BlockNode, CanonDoc, InlineNode, TableNode};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/table-style-resolution";

// ── helpers ──────────────────────────────────────────────────────────────
fn first_table(doc: &CanonDoc) -> &TableNode {
    doc.blocks
        .iter()
        .find_map(|b| match &b.block {
            BlockNode::Table(t) => Some(t.as_ref()),
            _ => None,
        })
        .expect("document should contain at least one table")
}

/// Collect all tables from the document body in order.
fn all_tables(doc: &CanonDoc) -> Vec<&TableNode> {
    doc.blocks
        .iter()
        .filter_map(|b| match &b.block {
            BlockNode::Table(t) => Some(t.as_ref()),
            _ => None,
        })
        .collect()
}

/// Get the first paragraph in a table cell.
fn cell_first_paragraph(table: &TableNode, row: usize, col: usize) -> &stemma::ParagraphNode {
    let cell = &table.rows[row].cells[col];
    cell.blocks
        .iter()
        .find_map(|b| match b {
            BlockNode::Paragraph(p) => Some(p),
            _ => None,
        })
        .expect("cell should contain at least one paragraph")
}

/// Get the first text node in a table cell.
fn cell_first_text_node(table: &TableNode, row: usize, col: usize) -> &stemma::TextNode {
    let cell = &table.rows[row].cells[col];
    for block in &cell.blocks {
        if let BlockNode::Paragraph(p) = block {
            for inline in p.all_inlines() {
                if let InlineNode::Text(t) = inline {
                    return t;
                }
            }
        }
    }
    panic!("cell ({row},{col}) should contain at least one text node")
}

/// Find a nested table inside a cell.
fn nested_table(table: &TableNode, row: usize, col: usize) -> &TableNode {
    let cell = &table.rows[row].cells[col];
    cell.blocks
        .iter()
        .find_map(|b| match b {
            BlockNode::Table(t) => Some(t.as_ref()),
            _ => None,
        })
        .expect("cell should contain a nested table")
}

// ── Border conflict: cell borders vs table style borders (§17.4.39-44) ──

/// MS-OI29500 §2.1.169: Cell border vs table style border weight resolution.
///
/// Cell (1,0) in a 2x2 table has explicit thin blue tcBorders (sz=4, weight=4).
/// The table style provides thick red borders (sz=18, weight=18).
///
/// Per MS implementation, weight-based resolution applies everywhere.
/// The heavier table border (weight=18) wins over the lighter cell border
/// (weight=4) on all edges.
#[test]
fn spec_cell_border_wins_over_table_border() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "border-conflict-cell-vs-table");
    let table = first_table(&doc);

    // Cell (1,0) has explicit blue tcBorders, but table border is heavier.
    let cell_10 = &table.rows[1].cells[0];
    let cell_borders = cell_10
        .formatting
        .borders
        .as_ref()
        .expect("cell (1,0) should have borders after conflict resolution");

    // MS-OI29500: table border (red/18, weight=18) wins over cell border
    // (blue/4, weight=4) on all edges including table edges.
    for (name, edge) in [
        ("top", &cell_borders.top),
        ("bottom", &cell_borders.bottom),
        ("left", &cell_borders.left),
        ("right", &cell_borders.right),
    ] {
        let border = edge
            .as_ref()
            .unwrap_or_else(|| panic!("cell (1,0) border edge '{name}' should be present"));
        assert_eq!(
            border.size,
            Some(18),
            "cell (1,0) {name}: table red/18 (weight=18) beats cell blue/4 (weight=4)"
        );
        assert_eq!(
            border.color.as_deref(),
            Some("FF0000"),
            "cell (1,0) {name}: table red wins by weight"
        );
    }

    // Cell (0,0) has no explicit tcBorders — gets table-cascaded borders.
    let cell_00 = &table.rows[0].cells[0];
    let borders_00 = cell_00
        .formatting
        .borders
        .as_ref()
        .expect("cell (0,0) should have borders from table cascade");
    let top_00 = borders_00
        .top
        .as_ref()
        .expect("cell (0,0) top should have border from table cascade");
    assert_eq!(
        top_00.size,
        Some(18),
        "cell (0,0) top border should be red/18 from table cascade"
    );
    assert_eq!(
        top_00.color.as_deref(),
        Some("FF0000"),
        "cell (0,0) top border color should be red from table cascade"
    );
}

// ── Conditional firstRow run formatting (§17.7.6.2) ────────────

/// ISO 29500-1 §17.7.6.2: Conditional formatting run properties.
///
/// Table style's firstRow tblStylePr sets bold + sz=28 (14pt) in rPr.
/// Runs in header row cells (with no direct bold/size) should inherit
/// these from the conditional formatting.
///
/// This differs from the table-cascade test (spec_conditional_run_props_bold)
/// by also testing font size, not just bold.
#[test]
fn spec_conditional_firstrow_run_formatting() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "conditional-font-formatting");
    let table = first_table(&doc);

    // First row: text should be bold from conditional rPr
    let text_00 = cell_first_text_node(table, 0, 0);
    assert!(
        text_00.marks.contains(&stemma::Mark::Bold),
        "text in first row cell (0,0) should be bold from conditional rPr"
    );

    let text_01 = cell_first_text_node(table, 0, 1);
    assert!(
        text_01.marks.contains(&stemma::Mark::Bold),
        "text in first row cell (0,1) should be bold from conditional rPr"
    );

    // First row: font size should be 28 half-points (14pt) from conditional rPr
    assert_eq!(
        text_00.style_props.font_size,
        Some(28),
        "text in cell (0,0) should have font_size=28 (14pt) from conditional rPr"
    );

    // Data rows: text should NOT be bold
    let text_10 = cell_first_text_node(table, 1, 0);
    assert!(
        !text_10.marks.contains(&stemma::Mark::Bold),
        "text in data row cell (1,0) should not be bold"
    );
}

// ── Conditional firstRow + lastRow paragraph alignment (§17.7.6.1) ─

/// ISO 29500-1 §17.7.6.1: Conditional formatting paragraph properties.
///
/// Table style's firstRow tblStylePr sets jc=center in pPr.
/// Table style's lastRow tblStylePr sets jc=right in pPr.
/// Paragraphs in first row should be center-aligned, last row right-aligned,
/// middle rows should have no alignment.
#[test]
fn spec_conditional_firstrow_paragraph_alignment() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "conditional-paragraph-alignment");
    let table = first_table(&doc);

    // First row: paragraphs should be center-aligned from conditional pPr
    let para_00 = cell_first_paragraph(table, 0, 0);
    assert_eq!(
        para_00.align,
        Some(stemma::Alignment::Center),
        "paragraph in first row cell (0,0) should be center-aligned from conditional pPr"
    );

    let para_01 = cell_first_paragraph(table, 0, 1);
    assert_eq!(
        para_01.align,
        Some(stemma::Alignment::Center),
        "paragraph in first row cell (0,1) should be center-aligned from conditional pPr"
    );

    // Middle rows: no conditional alignment → defaults to Left (MS-OI29500 2.1.45)
    let para_10 = cell_first_paragraph(table, 1, 0);
    assert_eq!(
        para_10.align,
        Some(stemma::Alignment::Left),
        "paragraph in middle row cell (1,0) should default to Left (no conditional override)"
    );

    let para_20 = cell_first_paragraph(table, 2, 0);
    assert_eq!(
        para_20.align,
        Some(stemma::Alignment::Left),
        "paragraph in middle row cell (2,0) should default to Left (no conditional override)"
    );

    // Last row: paragraphs should be right-aligned from conditional pPr
    let para_30 = cell_first_paragraph(table, 3, 0);
    assert_eq!(
        para_30.align,
        Some(stemma::Alignment::Right),
        "paragraph in last row cell (3,0) should be right-aligned from conditional pPr"
    );

    let para_31 = cell_first_paragraph(table, 3, 1);
    assert_eq!(
        para_31.align,
        Some(stemma::Alignment::Right),
        "paragraph in last row cell (3,1) should be right-aligned from conditional pPr"
    );
}

// ── Nested table style independence (§17.4.38) ──────────────────────────

/// ISO 29500-1 §17.4.38: A table nested inside another table's cell
/// should resolve its own style independently.
///
/// Outer table has green style (C6EFCE shading). Inner table in cell (1,0)
/// has orange style (FBE5D6 shading). The inner table's cells should show
/// orange shading, not green — styles do not cascade between tables.
#[test]
fn spec_nested_table_independent_style() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "nested-table-style-inherit");
    let outer = first_table(&doc);

    // Outer table cell (0,0): fixture shading is in wholeTable tblStylePr only,
    // which is discarded per MS-OI29500 §17.18.89. No shading expected.
    // TODO: update fixture to use root-level tcPr/shd instead of wholeTable tblStylePr
    // to properly test nested table style independence.
    assert!(
        outer.rows[0].cells[0].formatting.shading.is_none(),
        "outer cell (0,0): wholeTable discarded per MS-OI29500 §17.18.89, no shading"
    );

    // Inner table in cell (1,0): should have orange shading from inner style
    let inner = nested_table(outer, 1, 0);
    assert_eq!(inner.rows.len(), 2, "inner table should have 2 rows");

    // Inner table also only has shading in wholeTable tblStylePr — discarded.
    // TODO: update fixture to use root-level tcPr/shd for proper nested style test.
    assert!(
        inner.rows[0].cells[0].formatting.shading.is_none(),
        "inner cell (0,0): wholeTable discarded per MS-OI29500 §17.18.89, no shading"
    );
    assert!(
        inner.rows[1].cells[0].formatting.shading.is_none(),
        "inner cell (1,0): wholeTable discarded per MS-OI29500 §17.18.89, no shading"
    );
}

// ── Table-level properties from style (§17.4.63) ───────────────

/// ISO 29500-1 §17.4.63: Table style tblPr with alignment (jc) and
/// indent (tblInd) should propagate to the table when there are no
/// direct overrides.
///
/// Table 1: no direct alignment/indent — should inherit center + 360tw.
/// Table 2: direct jc=right override — alignment from direct, indent from style.
///
/// Currently, TableFormatting does not carry alignment or indent fields,
/// so these properties are lost during style resolution.
#[test]
fn spec_table_style_provides_indent_and_alignment() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "table-style-indent-alignment");
    let tables = all_tables(&doc);
    assert!(
        tables.len() >= 2,
        "should have at least 2 tables, got {}",
        tables.len()
    );

    // Table 1: should inherit center alignment and 360tw indent from style.
    assert_eq!(
        tables[0].formatting.alignment,
        Some(stemma::Alignment::Center),
        "table 1 should have center alignment from style"
    );
    assert_eq!(
        tables[0].formatting.indent,
        Some(360),
        "table 1 should have 360tw indent from style"
    );

    // Table 2: should have right alignment from direct override, indent from style.
    assert_eq!(
        tables[1].formatting.alignment,
        Some(stemma::Alignment::Right),
        "table 2 should have right alignment from direct override"
    );
    assert_eq!(
        tables[1].formatting.indent,
        Some(360),
        "table 2 should have 360tw indent from style"
    );
}

// ── Row banding alternation (§17.7.6) ───────────────────────────────────

/// ISO 29500-1 §17.7.6: band1Horz applies to odd-indexed rows (0, 2, 4...),
/// band2Horz applies to even-indexed rows (1, 3, 5...).
///
/// This tests a 6-row table whose style has band1Horz/band2Horz conditionals
/// but NO explicit tblStyleRowBandSize. Per MS-OI29500 §17.7.6.7, Word defaults
/// band size to 0 when absent, meaning no banding is applied.
/// The base spec says default is 1, but we follow MS behavior.
#[test]
fn spec_row_banding_alternates_correctly() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "row-banding-alternation");
    let table = first_table(&doc);
    assert_eq!(table.rows.len(), 6, "table should have 6 rows");

    // MS-OI29500: band size absent → defaults to 0 → no banding applied.
    for row_idx in 0..6 {
        assert!(
            table.rows[row_idx].cells[0].formatting.shading.is_none(),
            "row {row_idx}: band size absent (MS default 0) means no banding shading"
        );
    }
}
